module piso_shift_register_6bit(
    input clk,
    input rst,
    input load,
    input [5:0] parallel_in,

    output reg serial_out
);

reg [5:0] reset_reg;  // Internal shift register

// PISO Shift Register logic
always @(posedge clk) begin
    if (rst)
        reset_reg <= 6'b000000;
    else if (load)
        reset_reg <= parallel_in;
    else
        reset_reg <= {1'b0, reset_reg[5:1]};
end

// Serial output
always @(reset_reg) begin
    serial_out = reset_reg[0];
end

endmodule
